var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"오늘은 길을 걷다 빗물에 미끄러져서 전봇대에 코를 부딪혔다고?","JPN":"今日は道を歩いていて、雨水に滑って電柱に鼻をぶつけたと？","ENG":"So you smashed your nose against a utility pole after slipping in the rain while walking?","TWN":"你今天是走在路上，因為雨水滑倒，結果撞上電線桿、撞到鼻子了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇도다.","JPN":"そうだ。","ENG":"Correct.","TWN":"就是這樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"다음엔 넘어지면서 보드에 올라타면서, 그대로 내리막길을 질주했다는 거지?","JPN":"それで姿勢を崩したままボードに乗っちゃって、そのまま下り道を疾走したと。","ENG":"Then you fell onto a board and raced downhill on it?","TWN":"然後是跌倒時順勢踩上滑板，一路往下坡衝？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흔히 있는 일이니라.","JPN":"よくあることなのだ。","ENG":"It is a common occurrence.","TWN":"這是常有的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"가속도가 붙은 채로 소화전에 충돌… 그대로 날아올라 전깃줄에 걸려 감전… 달리는 버스 위로 떨어져 놀란 기사가 급정지함과 동시에 정면으로 날아가서…","JPN":"加速度がついたまま消火栓に衝突……そのまま飛び上がって電線に引っかかって感電……走るバスの上に落ちて驚いた運転手が急停止することと同時に正面に飛ばされて……","ENG":"Crashing into a fire hydrant while accelerating... Then flying straight into the air, getting electrocuted after getting caught in the electric wire... Falling on top of a moving bus, causing the startled bus driver to suddenly stop, and flying straight ahead...","TWN":"你在加速狀態下撞上消防栓……整個人飛起來掛在電線上觸電……又掉到行進中的公車車頂，嚇得司機緊急煞車，你又直接飛出去……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"으흠… 아무튼 이 뒤로 연달아 6번의 사고가 더 일어났구나.","JPN":"ふーん……とにかく、それから6回の事故が相次いだんだな。","ENG":"Hmm... Anyway, it looks like you got into six more accidents after that.","TWN":"嗯……總之在這之後，又接連發生了6起事故。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"더 말해 뭐하겠느냐.","JPN":"言わずともわかるであろう。","ENG":"What more is there for me to say?","TWN":"我無言以對。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"선생님! 모모가 얼마나 다친 건가요?!","JPN":"先生！　モモって、どれほど怪我したんですか！？","ENG":"Doctor! Is Momo okay?!","TWN":"醫生！莫莫到底傷得多重？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"여기에 쓰여진 대로라면 전치 6개월은 거뜬하겠네요.","JPN":"ここに書かれている通りだと、全治6か月はなるでしょうね。","ENG":"Reading what's written here, it should take about six months to fully heal.","TWN":"照這裡的記錄來看，至少需要休養6個月。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"전치 6개월? 그 정도로 많이 다친 건가요?!","JPN":"全治6か月？　そんなに大怪我なんですか！？","ENG":"Six months? Is she hurt that severely?!","TWN":"6個月？！她傷得這麼重嗎？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"좀 더 직설적으로 표현하자면… 살아있는 게 기적이라고 봐야할 정도입니다.","JPN":"もっとズバリ言うと……生きているのが奇跡なんです。","ENG":"To put it more bluntly... It's a miracle she's still alive.","TWN":"我說得更直接一點……她還活著本身就是奇蹟了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저… 실은 오는 길에 모모가 때를 써서 사탕을 하나 사줬는데요.","JPN":"あの……実はここに来る途中にモモが我がまま言うからキャンディを1つ買ってあげたんです。","ENG":"I... bought Momo a piece of candy on the way.","TWN":"那個……其實在來的路上，莫莫吵著要吃糖，我就買了一顆給她……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"혹시 당분이 부상에 악영향을 줄까요?!","JPN":"もしかして、糖分が怪我に悪影響を与えることってありますか！？","ENG":"Could the sugar have negative effects on her injuries?!","TWN":"糖分會不會對傷勢有不良的影響？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그, 그렇게까지 걱정하지 않으셔도 됩니다. 검진 결과, 몸에 특별한 이상은 없었으니까요.","JPN":"そ、そこまで心配する必要はないですよ。検診の結果、体に別状はなかったんですから。","ENG":"Y-you don't have to worry that much. According to the examinations, there's nothing wrong with her.","TWN":"不、不用那麼擔心。根據檢查結果，她的身體並沒有異常。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"당연하지 않느냐? 이 몸은 마왕이다.","JPN":"当然だ。吾輩は魔王なのだぞ。","ENG":"Of course, there's not! I am a Demon Lord!","TWN":"那是當然的吧？我可是魔王。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴우, 다행이네요. 이번에도 운이 좋았나 봐요.","JPN":"ふう、よかったですね。今度も運がよかったみたいです。","ENG":"Phew, that's good to hear. Guess she got lucky again.","TWN":"呼，那真是太好了。看來這次也算運氣不錯。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"글쎄요. 운이 좋았다고 하기엔 이번 달만 벌써 병원을 아홉 번째 찾아오셨습니다.","JPN":"どうでしょう。運がよかったことにしては、今月に入ってもう9番目の訪問ですよ。","ENG":"I don't think it's luck. This is her ninth visit to the hospital this month.","TWN":"是啊。雖然這麼說，但光是這個月，你們已經來醫院第九次了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"제가 미신은 믿지 않는 편입니다만, 두 분에겐 무당집이라도 알아보는 걸 진지하게 권해드리고 싶네요.","JPN":"私は迷信を信じない方なんですが、お二人には祓い屋でも探してみた方がいいんじゃないでしょうかね。","ENG":"I don't believe in superstitions, but I strongly advise you to take her to see a shaman.","TWN":"雖然我不太迷信，但真心建議你們要不要找個巫師？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"음? 의료보험이라고?","JPN":"うん？　医療保険？","ENG":"Hmm? Medical insurance?","TWN":"嗯？醫療保險？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 의사선생님이 만일을 대비하는 게 좋다면서 몇 군데 소개해주셨어요.","JPN":"はい、医者さんが万が一に備えた方がいいっていくつか紹介してくれたんです。","ENG":"Yes, the doctor recommended a few just to be safe.","TWN":"對。醫生說為了以防萬一，介紹了幾種方案。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음… 요즘에는 별의별 보험이 다 있네. 다이브 실종 특약 같은 것도 있구나.","JPN":"ふーん……最近は色んな保険があるわね。ダイブ失踪特約とかもあるじゃない。","ENG":"Hmm... There are all kinds of insurance these days. There are even ones with special conditions for going missing on dives.","TWN":"唔……現在的保險還真是五花八門，還有潛水失蹤的附加條款。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 오늘 외출이라도 나가시나 봐요?","JPN":"グレモリーさんは、今日お出かけなんですか？","ENG":"Gremory, are you going out today?","TWN":"葛茉莉小姐今天要出門啊？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 눈치챘어?","JPN":"あら、気付いた？","ENG":"Oh, did you notice?","TWN":"哎呀，被你發現啦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그야 평소보다 덜 취해계신 것 같아서요.","JPN":"いつもより酔ってないなーと思って。","ENG":"Well, you seem less drunk than usual.","TWN":"因為你看起來比平常清醒一點。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 니콜 양은 은근히 예리해서 거짓말도 못하겠다니까.","JPN":"ふふっ、ニコルちゃんは鋭くて嘘もつけないわね。","ENG":"Hah hah, you're so keen that I can't lie to you, Nicole.","TWN":"呵呵，妮可小姐其實挺敏銳的，害我都不能說謊呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"간만에 만화방이나 좀 다녀오려고 해. 꼬마 주인님이랑.","JPN":"久しぶりにマンガ喫茶に行ってこようと思ったの。王様とね。","ENG":"I'm thinking of going to the comic book store with our little majesty.","TWN":"我好久沒去漫畫店了，想跟小主人一起去一趟。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모와 만화방이요?","JPN":"モモとマンガ喫茶ですか？","ENG":"The comic book store with Momo?","TWN":"你要和莫莫去漫畫店嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"갖고 싶은 책이 있으면 말해. 내가 사줄 테니까.","JPN":"欲しい本があったら言ってちょうだい。アタシが買ってあげる。","ENG":"If there are any books you want, let me know. I'll buy them for you.","TWN":"有想要的書就說吧，我買給你。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"괜찮아요. 요즘 매출이 저조해서 새로운 칵테일 연구나 해보려고요.","JPN":"大丈夫ですよ。最近売り上げがよくないから、新しいカクテルでも研究しようと思ってます。","ENG":"It's all right. Sales are low these days, so I was thinking of researching new cocktail recipes.","TWN":"不用了。最近營業額不太好，我想研究一下新的雞尾酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"귀찮아.","JPN":"面倒だ。","ENG":"What a bother.","TWN":"真麻煩。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"사탕도 사줄게.","JPN":"キャンディも買ってあげるわ。","ENG":"I'll buy you candy.","TWN":"我也會買糖給你。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜, 이 몸이 없는 동안 가게를 잘 관리하는 것이다.","JPN":"ニコル、吾輩がいない間にちゃんと店番するのだぞ。","ENG":"Nicole, it is your duty to manage the shop while I'm not here.","TWN":"妮可，我不在的時候，店裡就交給你了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"해지기 전에는 돌아올게. 그때까지만 부탁해.","JPN":"日が沈む前には戻ってくるね。その時までお願い。","ENG":"We'll be back before sundown. Until then, you are in charge here.","TWN":"我會在日落前回來，在那之前就拜託你了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"물론이죠. 걱정 말고 다녀오세요.","JPN":"もちろんですよ。心配しないで行ってらっしゃい。","ENG":"Of course. Don't worry and have fun.","TWN":"沒問題，請放心出門吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨가 같이 있으니, 모모 걱정은 한동안 안 해도 되겠네요.","JPN":"グレモリーさんが一緒だと、しばらくモモのことは心配しなくてもよさそうですね。","ENG":"Since Momo is with Gremory, I won't have to worry about her for a while.","TWN":"既然有葛茉莉小姐陪著，暫時也不用太擔心莫莫了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자, 손님들이 오시기 전에 레몬이나 미리 손질해 둘까요?","JPN":"さて、お客さんが来る前にレモンを切っておきましょうか？","ENG":"Now, maybe I should slice some lemons before our guests arrive.","TWN":"好，在客人來之前先處理好檸檬吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 그레모리 씨가 만화에 너무 몰두한 나머지 모모를 혼자 내버려두기라도 한다면…","JPN":"でも、グレモリーさんがマンガに没頭しすぎてモモを1人にしたりしたら……","ENG":"But what if Gremory gets absorbed into reading comics and leaves Momo all alone...","TWN":"不過要是葛茉莉小姐看漫畫看到忘我，把莫莫一個人丟著……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"에이, 괜한 걱정은 말자고요. 제가 이 가게에 취업하기 전에도 두 분은 잘 지내왔는 걸요.","JPN":"もう、余計な心配はやめましょう。私がこの店で働く前にも2人でちゃんとやってきたんですから。","ENG":"Ugh, let's stop worrying about nothing. Those two were fine even before I joined this bar.","TWN":"不、不要想那麼多了。畢竟在我來這裡工作前，她們也是這樣過來的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"분명 제가 없더라도 잘 지낼 거예요.","JPN":"私がいなくても、きっとちゃんとやってるはずです。","ENG":"I'm sure they'll do just fine without me.","TWN":"就算沒有我，她們一定也可以好好相處。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"굳이… 제가 없더라도 말이죠.","JPN":"あえて……私がいなくてもね。","ENG":"Just fine... without me.","TWN":"即使……沒有我。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 어서오세요!","JPN":"あっ、いらっしゃいませ！","ENG":"Oh, welcome!","TWN":"啊，歡迎光臨！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조용하군. 내가 첫손님인 모양이지?","JPN":"静かだな。私が初めての客なのか？","ENG":"It's so quiet in here. Am I your first customer?","TWN":"很安靜呢，看來我是第一位客人。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네, 여기 앉으세요. 오늘은 어떤 걸로 드릴까요?","JPN":"はい、こちらにどうぞ。今日は何にしますか？","ENG":"Yes, please have a seat. What can I get you today?","TWN":"對啊，請坐這邊。今天想來點什麼呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"늘 주문하던 걸로 부탁하겠네.","JPN":"いつもので。","ENG":"I'll have the usual.","TWN":"老樣子就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"평소보다 일찍 오셨네요.","JPN":"早かったですね、今日は。","ENG":"You're here earlier than usual.","TWN":"您今天來得比平常早呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK_02"},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일이 예정보다 이른 시간에 끝났거든. 딱히 백수라서 그런 건 아니라네.","JPN":"仕事が予定より早く終わったのでね。別に無職だからではない。","ENG":"Work ended earlier than scheduled. It's not because I'm unemployed or anything.","TWN":"工作比預期早結束，可不是失業喔。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"바깥에서 어떤 일을 하고 계시건 여가를 즐길 시간이 있다는 건 좋다고 생각해요.","JPN":"外でどんな仕事をしていても、暇を楽しむ時間があるというのはいいと思いますよ。","ENG":"I think it's great that you can enjoy your free time no matter what job you have.","TWN":"不管在外面做什麼，只要能享受片刻悠閒的時光，我覺得都是好事。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"돈을 아무리 열심히 벌더라도, 사람의 마음을 채워주는 건 결국 한잔 술에 담긴 여유니까요.","JPN":"いくら頑張ってお金を稼いでも、人の心を満たしてくれるのは結局1杯のお酒ですから。","ENG":"Doesn't matter how hard you work to make money, because what fills a person's heart is a leisurely glass of alcohol.","TWN":"無論再怎麼努力賺錢，能填滿人心的，終究還是一杯酒裡的從容呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"재미있는 표현이로군.","JPN":"面白い表現だな。","ENG":"That’s an interesting expression.","TWN":"這個說法真有趣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"헤헤, 책에서 봤던 걸 멋대로 인용했을 뿐이지만요.","JPN":"へへ、本で読んだのを勝手に引用しただけなんですけどね。","ENG":"Hehe, I'm just quoting from a book I read once.","TWN":"嘿嘿，我只是隨便引用書上看到的話而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 인문학 서적을 즐겨 읽는 편인 모양이지?","JPN":"そうか。人文学の本をよく読んでいるのかね？","ENG":"I see. So do you enjoy reading literature?","TWN":"原來如此。看來你很常閱讀人文類的書籍囉？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하… 비슷하죠.","JPN":"あはは……似たようなものです。","ENG":"Ah hah hah... Something like that.","TWN":"啊哈哈……差不多吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(으아, 순정만화에 나왔던 대사라곤 절대 말 못해요.)","JPN":"(うわあ、乙女マンガに出たセリフだなんて絶対に言えません。)","ENG":"(Agh, I can't tell him that it's a quote from a romance comic book.)","TWN":"（我絕對不能說那是少女漫畫裡的台詞。）"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…칵테일의 맛이 평소와 다른 것 같은데.","JPN":"……カクテルの味がいつもと違うようだが。","ENG":"...This cocktail tastes a little different from what I used to have.","TWN":"……雞尾酒的味道，好像跟平常不太一樣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 정말요? 죄송해요! 금방 다시 만들어 드리겠습니다!","JPN":"あっ、本当ですか？　すみません。すぐ作り直します！","ENG":"Oh, really? I'm sorry! I'll make you a new one right away!","TWN":"啊，真的嗎？對不起！我馬上幫您重做一杯！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 서두르지 않아도 돼.","JPN":"いや、焦らなくていい。","ENG":"There's no need to rush.","TWN":"不用，你別那麼急。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"怎麼了？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정거리가 남아있으면 어떤 칵테일을 만들더라도 결국 근심이 섞여 들어가게 되거든.","JPN":"心配事があると、どんなカクテルを作っても結局は心配が混ざってしまう。","ENG":"If you have any lingering concerns, they're bound to get mixed in with the cocktail.","TWN":"只要心裡還有煩惱，不管調什麼酒，最後都會混進憂慮的味道。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮다면 나에게 말해보지 않겠나?","JPN":"よかったら私に話してみないか？","ENG":"If it's okay, why don't you talk to me about it?","TWN":"如果不介意的話，要不要跟我聊聊？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"말해요? 어떤 걸요?","JPN":"話す？　何をですか？","ENG":"Talk? About what?","TWN":"聊聊？要聊什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 가지고 있는 걱정거리 말일세.","JPN":"君が持っているその心配事さ。","ENG":"About what you're concerned with.","TWN":"你心裡的煩惱。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"손님이 바텐더의 고민을 들어주지 말란 법은 없으니 말이야.","JPN":"客はバーテンダーの悩みを聞いてあげることができないという規則などないからな。","ENG":"Customers can listen to a bartender's worries. What do you think?","TWN":"沒有規定客人不能聽聽調酒師的心事嘛。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…감사합니다. 하지만 전 괜찮아요. 정말로요.","JPN":"……ありがとうございます。でも、私は大丈夫ですよ。本当に。","ENG":"...Thank you. But I'm good. Really.","TWN":"……謝謝您。但我沒事，真的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"불편한 얘기로 손님의 마음을 불편하게 하고 싶지 않기 때문인가?","JPN":"気まずい話で客の心を煩わせたくないからか？","ENG":"You don't want to make your customer feel uncomfortable with your personal matters?","TWN":"你是不想因為不舒服的話題，讓客人感到不自在嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하… 글쎄요?","JPN":"あはは……どうでしょう。","ENG":"Ah hah hah... I guess?","TWN":"啊哈哈……大概吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(애초에 성황청의 퇴마사가 악마를 돌보고 있다는 말을 어떻게 해요.)","JPN":"(そもそも聖皇庁のエクソシストが悪魔のお世話をしてるなんて言えるわけないじゃないですか。)","ENG":"(I can't tell that an exorcist from the Holy Curia is taking care of a devil!)","TWN":"（我是要怎麼說，聖皇廳的驅魔師在照顧惡魔啊。）"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하긴, 자네 같은 친절한 바텐더라면 충분히 그런 배려를 하고도 남겠지.","JPN":"確かに、君のような親切なバーテンダーなら十分そんな気遣いをしそうだな。","ENG":"I suppose a kind bartender like you would be more than considerate.","TWN":"也是。像你這麼溫柔的調酒師，當然會有這樣的顧慮。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 근심을 속에 담아두는 건 좋지 않은 버릇이야.","JPN":"だが、心配を心の中に溜め込んでおくのはよくない癖だよ。","ENG":"But it's not a good habit to keep your worries inside.","TWN":"但把煩惱藏在心裡，可不是個好習慣。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"근심과 술에 공통점이 있다면 나누기에 좋다는 거지.","JPN":"心配とお酒に共通点があるとしたら、分かち合うといいということだ。","ENG":"If there are any similarities between worries and alcohol, it's that they should be shared.","TWN":"要說煩惱和酒有個共同點，就是都很適合分享。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"근심은 나눌수록 줄어들고, 술맛은 배가 되니까.","JPN":"心配は分かち合うほど少なくなり、お酒の味はよくなる。","ENG":"Because when shared, worries lessen, and alcohol tastes better.","TWN":"煩惱越分越少，酒的滋味就會越來越濃。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"와아, 무척 좋은 표현이네요.","JPN":"わあ、とてもいい表現ですね。","ENG":"Wow, that's a really good way to put it.","TWN":"哇，好棒的說法。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"웹소설에서 읽었던 대사를 인용했을 뿐이라네.","JPN":"ネット小説で読んだセリフを引用しただけさ。","ENG":"I'm just quoting a line I read from an internet novel.","TWN":"我只是引用網路小說裡的台詞罷了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"푸흡, 뭐예요 그게.","JPN":"ぶふっ。なんですか、それ。","ENG":"Pfft! An internet novel?","TWN":"噗，什麼啦。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그것 보게. 영업용 미소가 아닌 진심으로 웃는 모습도 보기 좋지 않나?","JPN":"ほら。営業スマイルではなく、本当の笑い顔もいいではないか。","ENG":"See? It's so much better to see a genuine smile rather than a business smile, don't you think?","TWN":"看吧，比起營業用的笑容，這樣真心的笑容不是更好看嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄송해요. 제가 가진 고민은 함부로 털어놓을 수 없는 거라서요.","JPN":"すみません。私の悩みは、簡単には言えないものなんです。","ENG":"I'm sorry. But it's not something I can just talk to anyone about.","TWN":"對不起。我心裡的煩惱不能隨便說出口。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"절대로 손님에게 제 진심을 보이기 싫다거나 그런 건 아니예요. 믿어주세요.","JPN":"絶対にお客様に私の本気を見せたくないとか、そういう意味じゃないんですよ。信じてください。","ENG":"It's not because I don't want to be sincere with you. I hope you understand.","TWN":"我並不是不想讓客人看見真正的我，這點請您相信我。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"추상적이어도 괜찮아.","JPN":"抽象的でも構わない。","ENG":"It's fine with it being vague.","TWN":"抽象一點也沒關係。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤 방식으로든, 속에 있는 것을 털어내는 행동이 중요한 거니까.","JPN":"どんな方法だろうと、心の中にあるものを打ち払うという行動が大事なのだからな。","ENG":"What's important is that you let it out, no matter the method.","TWN":"不論是哪種形式，把心裡的東西說出來這點本身就很重要。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음… 확신이 없다고 해야 할까요.","JPN":"うーん……確信がないっていうか。","ENG":"Mm... Maybe I should say that I'm not certain?","TWN":"唔……應該說我是少了信心吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확신?","JPN":"確信？","ENG":"Certain?","TWN":"信心？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가 올바른 선택을 하고 있는 건지… 이대로 지내도 괜찮은 건지… 그런 것에 대한 확신이요.","JPN":"自分が正しい選択をしているのか……このまま暮らしてていいのか……そんなことについての確信です。","ENG":"About if what I'm doing is right... If it's okay to keep living like this... That sort of certainty.","TWN":"我不知道自己是不是做出了正確的選擇……也不知道是否真的可以這樣過下去……我少了這些信心。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어쩌면 잘못되어 가고 있다는 걸 알면서도… 전 억지로 그 사실을 외면하고 있는 걸지도 몰라요.","JPN":"もしかしたら間違った方向に行ってるってわかっていながらも……私は無理やりその事実から目を背けているのかもしれません。","ENG":"Even though I know that it's wrong... Maybe I'm just forcing myself to ignore the truth.","TWN":"說不定我就是，明明知道事情正在走向錯誤的那邊……卻還是刻意忽視。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"결국 후회하게 될 선택을 하고… 그 결과를 마주할 자신이 없는 겁쟁이예요. 저는.","JPN":"結局後悔することになる選択をして……その結果と向き合う自信のない臆病者なんです、私は。","ENG":"Eventually, I'll regret my decision, and figure out that... I'm a coward who can't face the consequences.","TWN":"結果做出了會後悔的選擇……卻沒有勇氣去面對結果的膽小鬼。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후회하게 될 선택이라…….","JPN":"後悔することになる選択か……","ENG":"A decision you'll regret, you say?","TWN":"會後悔的選擇啊……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 시간을 되돌릴 수 있나?","JPN":"君は時間を巻き戻すことができるのか？","ENG":"Tell me. Do you have the ability to turn back time?","TWN":"你能讓時間倒流嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"에이, 그럴 리가요.","JPN":"ええ？　まさか。","ENG":"No, of course not.","TWN":"唉唷，怎麼可能。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"애초에 그런 게 가능한가요?","JPN":"そもそもそんなことって本当にできるんですか？","ENG":"Is that even possible?","TWN":"那種事本來就不可能吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 어째서 돌이킬 수도 없는 선택에 대해 걱정하고 있지?","JPN":"なら、どうして取り返すこともできない選択についてそこまで心配している？","ENG":"So, why are you concerned about making a decision that you cannot reverse?","TWN":"那你為什麼要為無法回頭的選擇而煩惱呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제 선택으로 말미암아 누군가 받게 될 상처와 좌절이 두렵거든요.","JPN":"私の選択で誰かが傷ついて挫折することが怖いんです。","ENG":"I'm afraid that my decision is going to hurt someone.","TWN":"我害怕因為我的選擇，會讓某些人受傷、失望。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"누구도 상처받지 않는 선택 같은 건 없는 건가?","JPN":"誰も傷つかない選択などはないのか？","ENG":"Is there an option where no one gets hurt?","TWN":"真有不會讓任何人受傷的選擇嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이건… 수평이 없는 저울 같은 거라고 생각해요.","JPN":"これは……平らになれない天秤のようなものだと思います。","ENG":"I think... this is like an uneven scale.","TWN":"我覺得……那就像一個沒有校準的天秤。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"결국 어느 한쪽으로 기울 수밖에 없는 거죠.","JPN":"結局は片方に傾くしかないんです。","ENG":"It has no choice but to lean to one side.","TWN":"最後總會向某一邊傾斜。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 자네는 이미 답을 알고 있는 것 같군.","JPN":"それなら君はすでに答えを知っているようだな。","ENG":"Then, it seems that you already have your answer.","TWN":"那看來你其實已經知道答案了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私がですか？","ENG":"Huh? I do?","TWN":"咦？我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 돌이킬 수 없다면, 결국 옳다고 믿는 쪽으로 나아가는 수밖에 없지 않나?","JPN":"ああ。取り返すことができないなら、結局は正しいと信じている方に進むしかないだろう。","ENG":"Sure. If there is no reversing it, all that's left is to move forward in the path you think is right, no?","TWN":"是啊。既然無法回頭，最終不就只能朝自己相信正確的方向前進嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시험지 위엔 정답이 있겠지만, 현실의 문제 앞에 진정한 정답이란 건 없다네.","JPN":"試験の問題には答えがあるだろうが、現実の問題に真なる答えなどないのだよ。","ENG":"Tests on paper may have a correct answer, but problems in real life do not.","TWN":"考卷上或許有標準答案，但現實的問題，從來沒有正確答案。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결단을 내려야만 하는 순간이 왔을 때, 자넨 옳다고 믿는 선택을 하면 되는 걸세.","JPN":"決断をすべき瞬間が来た時、君が正しいと信じる選択をすればいいだけさ。","ENG":"When the time comes to make a decision, what's important is that you choose what you think is right.","TWN":"必須下定決心的時刻到來的時候，只要選擇你相信是正確的那條路就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가 감당할 수 있을까요? 그 결정이… 저를 믿어준 사람들을 등지게 된다 하더라도?","JPN":"私は耐えられるんでしょうか？　その決定が……私を信じてくれた人たちを裏切ることになっても。","ENG":"Do you think I can handle it? Even if... that decision will betray the people who trust me?","TWN":"那我能承受得了嗎？那個決定……即使會背棄曾經信任我的人？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람은 때론 가시밭길이란 걸 알면서도 나아가야 할 때가 있는 법일세.","JPN":"人は時にいばらの道だとわかっていながらも進まないといけない時がある。","ENG":"There are times when a person must keep moving despite knowing that what lies ahead is a difficult path.","TWN":"人有時候明知道前方佈滿荊棘，也只能向前邁進。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"중요한 건, 때늦은 후회가 이미 내린 선택마저 그르치게 둬선 안 된다는 거지.","JPN":"大事なのは、手遅れの後悔がすでに選択したことまで駄目にするように放っておいてはいけないということだ。","ENG":"Just remember not to let regrets ruin what you've already decided on.","TWN":"重要的是別讓遲來的後悔，否定了你已經做出的選擇。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 상처를 입을 수밖에 없다면 충분히 대비해 두게.","JPN":"だから、傷つくしかないのなら十分備えておくのだよ。","ENG":"So, if you know you're going to hurt someone, be fully prepared for it.","TWN":"所以如果注定會受傷，那就事先做好準備吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님은 돌이킬 수 없는 선택을 하고서… 후회하지 않으셨나요?","JPN":"お客様は取り返しのつかない選択をして……後悔しなかったんですか？","ENG":"Have you ever regretted a decision... that you couldn't undo?","TWN":"那您呢？您做出無法回頭的選擇後……沒有後悔過嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선택은 순간이지만 선택을 통해 짊어진 책임은 평생 따라가는 걸세.","JPN":"選択は一瞬で終わるが、選択することで背負うことになった責任は一生ついてくる。","ENG":"Making a decision is in the moment, but the responsibility it entails will follow you for a lifetime.","TWN":"選擇只是一瞬間，但隨之背負的責任卻會伴隨一生。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후회 같은 걸 해봐야, 내가 짊어진 업보에 스스로 짓눌리는 꼴이 될 뿐이지.","JPN":"後悔などしても、自分が背負っている業に踏みつけられる様になるだけだからな。","ENG":"In the end, regrets will only make me feel the weight of my karma.","TWN":"就算後悔，也只會被自己背負的業障壓垮而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"선택이 수평 없는 저울이라면, 후회는 저울 양쪽의 무게를 모두 가볍게 만드는 짓이라네.","JPN":"選択が平らになることのない天秤なら、後悔はその天秤の両方とも軽くさせてしまう行為だよ。","ENG":"If choices are like an uneven scale, regrets are what make both sides lighter.","TWN":"如果選擇是一個沒有校準的天秤，那麼後悔就是讓天秤兩端都變得更輕的行為。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 무책임한 짓을 하기엔, 난 너무 오래 살았거든.","JPN":"そんな無責任なことをするには、私はあまりにも長生きしている。","ENG":"And I've lived long enough to know not to do something so irresponsible.","TWN":"我已經活得太久，做不出那麼不負責任的事了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…그러네요. 저희 같은 어른들이 후회 같은 걸 해선 안 되는 거겠죠.","JPN":"……そうですね。私たちみたいな大人が後悔なんかしちゃダメなんでしょう。","ENG":"...I see. So adults like us shouldn't have regrets.","TWN":"……說得也是。像我們這種大人，確實不該輕易後悔呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 딱히 어른이 후회를 하면 안 된다고는 안 했는데.","JPN":"うむ？　別に大人が後悔してはいけないとは言っていないが。","ENG":"Hmm? I didn't say that adults shouldn't have regrets.","TWN":"嗯？我可沒說大人不能後悔喔。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 그치만 손님께선 저랑 나이가 별로 차이가…","JPN":"えっ？　でもお客様って、私と……","ENG":"Huh? But you and I seem to be around the same age...","TWN":"咦？可是您看起來跟我年紀差不多……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…의외로 많이 동안이신 모양이네요.","JPN":"……意外と結構若く見える方なんですね。","ENG":"...Or you look surprisingly young for your age.","TWN":"……意外地很凍齡呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네. 자주 듣는 얘기야.","JPN":"ありがとう。よく言われる。","ENG":"Thanks. I get that a lot.","TWN":"謝謝，我常聽到這句話。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 손님 잔이 비어 있었네요.","JPN":"あっ、お客様。グラスが空っぽでした。","ENG":"Oh, your glass is empty, sir.","TWN":"啊，您的杯子空了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다음은 제가 살게요. 고민상담을 해주신 답례로요.","JPN":"次の1杯は私がおごります。悩みの相談に乗ってくれたお礼で。","ENG":"The next one is on me. In return for giving me advice.","TWN":"下杯算我的，就當作是諮詢煩惱的謝禮。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상담이라기엔 부끄럽군. 반쯤은 내 지난 날에 대한 하소연일 뿐이었으니까.","JPN":"相談とは恥ずかしいな。ほぼ自分の過去について愚痴をこぼしただけだったからな。","ENG":"I wouldn't call it advice, as half of it was me talking about my past.","TWN":"也說不上什麼諮詢，有一半都只是針對我的過去發牢騷而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 공짜술을 마다할 이유는 없겠지.","JPN":"だが、ふるまい酒を断る理由はない。","ENG":"But I'm not one to turn down free drinks.","TWN":"不過我沒理由拒絕免費的酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"헤헤, 어떤 걸로 드릴까요?","JPN":"へへ、どんなものにしますか？","ENG":"Hehe. What will it be?","TWN":"嘿嘿，那您想喝什麼呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 가장 좋아하는 걸로 부탁하지.","JPN":"君が一番好きなもので頼む。","ENG":"I'll have your favorite drink.","TWN":"就調你最喜歡的吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"알겠습니다!","JPN":"わかりました！","ENG":"Sure thing!","TWN":"好的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으앗?! 또 실패잖아?","JPN":"わあっ！？　また失敗？","ENG":"Oops?! I ruined it again.","TWN":"呃啊？！又失敗了？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄송해요. 예쁜 칵테일을 만들어드리고 싶었는데, 오늘따라 플로팅이 잘 안 되네요.","JPN":"すみません。綺麗なカクテルを作ってあげたかったのに、今日はフローティングがうまくいきませんね。","ENG":"I'm sorry. I wanted to make you a pretty cocktail, but I can't seem to make a float today.","TWN":"對不起。我想幫您調一杯漂亮的雞尾酒，但今天分層很不順。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 아까운 술을 버릴 필요는 없지. 내게 주게.","JPN":"そうだとしても、もったいないお酒を捨てるわけにはいかない。私にくれたまえ。","ENG":"That's no reason to throw out a good cocktail. Give it here.","TWN":"也不用因為這樣就浪費這杯酒，給我吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 하지만 괜찮으시겠어요? 맛이 섞여서 이상할 텐데.","JPN":"え？　でも、いいんですか？　味がごちゃごちゃになってるはずなんですよ？","ENG":"Huh? Are you sure about that? It's all mixed up, so it won't taste that great.","TWN":"咦？可是這樣真的可以嗎？味道都混在一起了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮다네. 술이 섞여도 결국 취하는 건 매 한가지니까.","JPN":"大丈夫さ。お酒が混ざっても結局酔っぱらうのは一緒だからな。","ENG":"It's all right. Mixed or not, I'll get drunk either way.","TWN":"沒關係。酒就算混在一起，最後還是一樣會醉。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에…….","JPN":"はあ……","ENG":"If you insist...","TWN":"好、好吧……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 방금 하신 그 말씀에도 뭔가 깊은 뜻이 담겨있는 거군요?!","JPN":"あっ、今のその言葉も何か意味深ですね！？","ENG":"Oh! What you said just now, does it also have a deeper meaning?!","TWN":"啊，剛剛那句話也別有深意對吧？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뒤섞인 칵테일을 마셔도 취하는 것처럼, 혼란스러운 경험에도 나름의 가치가 있다거나?!","JPN":"混ざったカクテルを飲んでも酔うみたいに、混乱する経験にもそれなりに価値があるとか！？","ENG":"Just like getting drunk on ruined drinks, even confusing experiences are still worth something?!","TWN":"就像喝下混合的雞尾酒也會醉一樣，混亂的經驗其實也有它的價值？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니… 그리 대단한 뜻은 없었는데…","JPN":"いや……大した意味はなかったのだが……","ENG":"No... I didn't imply anything like that...","TWN":"不……其實沒有那麼深層的含意……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그런가요? 저도 참.","JPN":"そ、そうなんですか？　私ったら。","ENG":"R-really? Oh...","TWN":"是、是這樣嗎？我真是的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 이 뒤섞인 칵테일에도 나름의 매력이 있다는 사실은 확실해.","JPN":"だが、この混ざってしまったカクテルにはそれなりの魅力があるということは確かだ。","ENG":"But I'm sure this ruined cocktail has its own charm.","TWN":"不過這杯混合的雞尾酒，確實有它的魅力。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"니콜 양 같은 바텐더를 만난 건, 나에게 있어 행운이라네.","JPN":"ニコル君のようなバーテンダーに出会ったのは、私にとって幸運だよ。","ENG":"I'm lucky to have met a bartender like you, Ms. Nicole.","TWN":"能遇到像妮可小姐這樣的調酒師，對我來說也是一種幸運。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"고맙습니다! 손님!","JPN":"ありがとうございます！　お客様！","ENG":"Thank you, sir!","TWN":"謝謝您，客人！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};